import type {
  SelectedClipPayload,
  SupabaseAdmin,
  TimelineState,
  ToolResult,
} from "../types.ts";
import { createShotWithGenerations, findShotForGenerations, resolveClipGenerationIds } from "./clips.ts";
import { createGenerationTask } from "./generation.ts";

const APPEND_SHOT_POSITION = 2_147_483_647;
const SUPPORTED_CREATE_TASK_TYPES = new Set([
  "text-to-image",
  "style-transfer",
  "subject-transfer",
  "scene-transfer",
  "image-to-video",
]);
const TASK_TYPE_TO_REFERENCE_MODE: Record<string, string> = {
  "style-transfer": "style",
  "subject-transfer": "subject",
  "scene-transfer": "scene",
};

function asTrimmedString(value: unknown): string | null {
  return typeof value === "string" && value.trim() ? value.trim() : null;
}

function asPositiveNumber(value: unknown): number | null {
  return typeof value === "number" && Number.isFinite(value) && value > 0 ? value : null;
}

function asStringArray(value: unknown): string[] {
  return Array.isArray(value)
    ? value.filter((item): item is string => typeof item === "string" && item.trim().length > 0)
      .map((item) => item.trim())
    : [];
}

export async function executeCreateTask(
  args: Record<string, unknown>,
  timelineState: TimelineState,
  selectedClips: SelectedClipPayload[] | undefined,
  supabaseAdmin: SupabaseAdmin,
): Promise<Pick<ToolResult, "result">> {
  const taskType = asTrimmedString(args.task_type);
  const prompt = asTrimmedString(args.prompt);
  if (!taskType || !prompt) {
    return { result: "create_task requires task_type and prompt." };
  }
  if (!SUPPORTED_CREATE_TASK_TYPES.has(taskType)) {
    return { result: `create_task does not support task_type ${taskType}.` };
  }

  const referenceImageUrls = asStringArray(args.reference_image_urls);
  if (taskType === "image-to-video" && referenceImageUrls.length < 2) {
    return { result: "create_task image-to-video requires at least two reference_image_urls." };
  }
  if (taskType !== "text-to-image" && taskType !== "image-to-video" && referenceImageUrls.length === 0) {
    return { result: `create_task ${taskType} requires reference_image_urls.` };
  }

  const selectedReferenceClips = selectedClips?.filter((clip) => referenceImageUrls.includes(clip.url)) ?? [];
  const generationIds = resolveClipGenerationIds(selectedReferenceClips, timelineState.registry, timelineState.config);
  let shotId = generationIds.length ? await findShotForGenerations(supabaseAdmin, generationIds) : null;
  let shotNote = "";
  const shotName = asTrimmedString(args.shot_name);
  if (!shotId && shotName && generationIds.length > 0) {
    shotId = await createShotWithGenerations(supabaseAdmin, {
      projectId: timelineState.projectId,
      shotName,
      generationIds,
      position: APPEND_SHOT_POSITION,
    });
    shotNote = ` Created shot ${shotName} (${shotId}).`;
  } else if (shotId) {
    shotNote = ` Reused shot ${shotId}.`;
  }

  const result = await createGenerationTask({
    project_id: timelineState.projectId,
    prompt,
    count: asPositiveNumber(args.count) ?? 1,
    task_type: taskType,
    reference_mode: TASK_TYPE_TO_REFERENCE_MODE[taskType],
    reference_image_url: referenceImageUrls[0],
    image_urls: taskType === "image-to-video" ? referenceImageUrls : undefined,
    shot_id: shotId ?? undefined,
  });
  return { result: `${result.result}${shotNote}`.trim() };
}

import {
  forwardRef,
  useImperativeHandle,
  useLayoutEffect,
  useState,
  type MutableRefObject,
} from 'react';
import { createPortal } from 'react-dom';
import type { GhostRect } from '@/tools/video-editor/lib/multi-drag-utils';

export interface DropIndicatorPosition {
  rowTop: number;
  rowHeight: number;
  rowLeft: number;
  rowWidth: number;
  lineLeft: number;
  ghostLeft: number;
  ghostTop: number;
  ghostWidth: number;
  ghostHeight: number;
  ghostLabel: string;
  label: string;
  isNewTrack: boolean;
  isNewTrackTop?: boolean;
  trackId?: string;
  /** When non-null, describes the kind of track that will be created. */
  newTrackKind: string | null;
  reject: boolean;
}

export interface DropIndicatorHandle {
  show(position: DropIndicatorPosition): void;
  showSecondaryGhosts(ghosts: GhostRect[]): void;
  hide(): void;
}

interface DropIndicatorProps {
  editAreaRef: MutableRefObject<HTMLElement | null>;
  onNewTrackLabel?: (label: string | null) => void;
}

export const DropIndicator = forwardRef<DropIndicatorHandle, DropIndicatorProps>(function DropIndicator(
  { editAreaRef, onNewTrackLabel },
  ref,
) {
  const [position, setPosition] = useState<DropIndicatorPosition | null>(null);
  const [secondaryGhosts, setSecondaryGhosts] = useState<GhostRect[]>([]);

  useImperativeHandle(ref, () => ({
    show(nextPosition) {
      setPosition(nextPosition);
    },
    showSecondaryGhosts(ghosts) {
      setSecondaryGhosts(ghosts);
    },
    hide() {
      setPosition(null);
      setSecondaryGhosts([]);
    },
  }), []);

  useLayoutEffect(() => {
    const editArea = editAreaRef.current;
    if (!editArea) {
      return undefined;
    }

    // Only show the "create new track" affordance when dragging below all rows
    // (not for kind-mismatch redirects — those resolve silently to a compatible track)
    const showNewTrack = position?.isNewTrack === true && position?.trackId === undefined;
    editArea.classList.toggle('drop-target-new-track', showNewTrack);

    if (showNewTrack) {
      const kind = position?.newTrackKind ?? 'visual';
      const where = position?.isNewTrackTop ? 'top' : 'bottom';
      onNewTrackLabel?.(`Drop to create new ${kind} track at ${where}`);
    } else {
      onNewTrackLabel?.(null);
    }

    return () => {
      editArea.classList.remove('drop-target-new-track');
      onNewTrackLabel?.(null);
    };
  }, [editAreaRef, onNewTrackLabel, position?.isNewTrack, position?.isNewTrackTop, position?.newTrackKind, position?.trackId]);

  if (!position || typeof document === 'undefined') {
    return null;
  }

  const labelLeft = position.lineLeft - 30;
  const labelTop = position.rowTop - 16;

  return createPortal(
    <>
      <div
        className={position.reject ? 'drop-indicator-row drop-indicator-row--reject' : 'drop-indicator-row'}
        style={{
          left: position.rowLeft,
          top: position.rowTop,
          width: position.rowWidth,
          height: position.rowHeight,
          zIndex: 99998,
        }}
      />
      {!position.isNewTrack && (
        <>
          <div
            className="drop-indicator-line"
            style={{ left: position.lineLeft, top: position.rowTop, height: position.rowHeight, zIndex: 99999 }}
          />
          <div
            className="drop-indicator-ghost"
            style={{
              left: position.ghostLeft,
              top: position.ghostTop,
              width: position.ghostWidth,
              height: position.ghostHeight,
              zIndex: 99998,
            }}
          >
            <span className="drop-indicator-ghost-label">{position.ghostLabel}</span>
          </div>
          <div
            className="drop-indicator-label"
            style={{ left: labelLeft, top: labelTop, zIndex: 100000 }}
          >
            {position.label}
          </div>
        </>
      )}
      {secondaryGhosts.map((ghost, i) => (
        <div
          key={i}
          className="drop-indicator-ghost"
          style={{
            left: ghost.left,
            top: ghost.top,
            width: ghost.width,
            height: ghost.height,
            zIndex: 99997,
            opacity: 0.6,
          }}
        />
      ))}
    </>,
    document.body,
  );
});

import { toErrorMessage } from "../../_shared/errorMessage.ts";
import { MAX_CONTEXT_TURNS } from "../config.ts";
import type {
  AgentSession,
  AgentSessionStatus,
  AgentTurn,
  LlmMessage,
  TimelineRow,
} from "../types.ts";
import type { AssetRegistry, TimelineConfig } from "../../../../src/tools/video-editor/types/index.ts";

export function isRecord(value: unknown): value is Record<string, unknown> {
  return typeof value === "object" && value !== null;
}

export function isSessionStatus(value: unknown): value is AgentSessionStatus {
  return value === "waiting_user"
    || value === "processing"
    || value === "continue"
    || value === "done"
    || value === "cancelled"
    || value === "error";
}

export function normalizeTurns(value: unknown): AgentTurn[] {
  if (!Array.isArray(value)) {
    return [];
  }

  return value.flatMap((item) => {
    if (!isRecord(item) || typeof item.content !== "string" || typeof item.timestamp !== "string") {
      return [];
    }

    const role = item.role;
    if (role !== "user" && role !== "assistant" && role !== "tool_call" && role !== "tool_result") {
      return [];
    }

    return [{
      role,
      content: item.content,
      attachments: Array.isArray(item.attachments) ? item.attachments : undefined,
      tool_name: typeof item.tool_name === "string" ? item.tool_name : undefined,
      tool_args: isRecord(item.tool_args) ? item.tool_args : undefined,
      timestamp: item.timestamp,
    }];
  });
}

export function createTurn(role: AgentTurn["role"], content: string): AgentTurn {
  return {
    role,
    content,
    timestamp: new Date().toISOString(),
  };
}

export function createToolTurn(
  role: Extract<AgentTurn["role"], "tool_call" | "tool_result">,
  toolName: string,
  content: string,
  toolArgs: Record<string, unknown>,
): AgentTurn {
  return {
    role,
    content,
    tool_name: toolName,
    tool_args: toolArgs,
    timestamp: new Date().toISOString(),
  };
}

export function normalizeSessionRow(row: Record<string, unknown>): AgentSession {
  return {
    id: typeof row.id === "string" ? row.id : "",
    timeline_id: typeof row.timeline_id === "string" ? row.timeline_id : "",
    user_id: typeof row.user_id === "string" ? row.user_id : "",
    status: isSessionStatus(row.status) ? row.status : "error",
    turns: normalizeTurns(row.turns),
    model: typeof row.model === "string" ? row.model : "openrouter",
    summary: typeof row.summary === "string" ? row.summary : null,
    created_at: typeof row.created_at === "string" ? row.created_at : "",
    updated_at: typeof row.updated_at === "string" ? row.updated_at : "",
  };
}

export function normalizeTimelineRow(row: Record<string, unknown>): TimelineRow {
  return {
    config: (row.config as TimelineConfig | null)
      ?? { output: { resolution: "1920x1080", fps: 30, file: "output.mp4" }, clips: [] },
    config_version: typeof row.config_version === "number" ? row.config_version : 1,
    asset_registry: (row.asset_registry as AssetRegistry | null) ?? { assets: {} },
    project_id: typeof row.project_id === "string" ? row.project_id : "",
  };
}

export function parseToolArgsSafely(rawArguments: unknown): {
  args: Record<string, unknown>;
  error: string | null;
} {
  if (typeof rawArguments !== "string" || !rawArguments.trim()) {
    return { args: {}, error: null };
  }

  try {
    const parsed = JSON.parse(rawArguments);
    // Accept null, empty arrays, etc. as "no args" — only reject non-object primitives like strings/numbers
    if (parsed === null || parsed === undefined) {
      return { args: {}, error: null };
    }
    if (typeof parsed !== "object") {
      console.warn(`[agent] Tool args parsed to non-object: ${typeof parsed} — ${rawArguments.slice(0, 100)}`);
      return { args: {}, error: null };
    }
    return { args: isRecord(parsed) ? parsed : {}, error: null };
  } catch (error: unknown) {
    console.warn(`[agent] Failed to parse tool args: ${rawArguments.slice(0, 200)}`);
    return {
      args: {},
      error: `Invalid tool arguments JSON: ${toErrorMessage(error)}`,
    };
  }
}

export function formatToolArgs(toolArgs: Record<string, unknown>): string {
  return JSON.stringify(toolArgs, null, 2);
}

export function summarizeStoredToolTurn(turn: AgentTurn): string {
  const toolName = turn.tool_name ?? "tool";
  if (turn.role === "tool_call") {
    return `Tool call ${toolName}:\n${formatToolArgs(turn.tool_args ?? {})}`;
  }

  return `Tool result ${toolName}: ${turn.content}`;
}

export function buildInitialMessages(
  systemPrompt: string,
  turns: AgentTurn[],
): LlmMessage[] {
  const messages: LlmMessage[] = [{ role: "system", content: systemPrompt }];

  // Only send the most recent turns to avoid blowing up the context window.
  const recentTurns = turns.length > MAX_CONTEXT_TURNS
    ? turns.slice(-MAX_CONTEXT_TURNS)
    : turns;

  for (const turn of recentTurns) {
    if (turn.role === "user") {
      messages.push({ role: "user", content: turn.content });
      continue;
    }

    if (turn.role === "assistant") {
      messages.push({ role: "assistant", content: turn.content });
      continue;
    }

    messages.push({
      role: "assistant",
      content: summarizeStoredToolTurn(turn),
    });
  }

  return messages;
}

export function extractAssistantText(message: { content?: unknown }): string {
  if (typeof message.content === "string") {
    return message.content.trim();
  }

  if (!Array.isArray(message.content)) {
    return "";
  }

  return message.content
    .flatMap((item) => {
      if (!isRecord(item)) {
        return [];
      }

      const text = item.text;
      return typeof text === "string" ? [text] : [];
    })
    .join("\n")
    .trim();
}

import { useCallback, useEffect, useMemo, useRef, useState } from 'react';
