type AgentChatMessageProps = {
  turn: AgentTurn;
};

type AgentChatToolGroupProps = {
  pairs: ToolCallPair[];
};

function formatAttachmentSummary(attachments: AgentTurn['attachments']) {
  if (!attachments?.length) {
    return null;
  }

  const imageCount = attachments.filter((attachment) => attachment.mediaType === 'image').length;
  const videoCount = attachments.length - imageCount;
  const parts = [
    imageCount > 0 ? `${imageCount} image${imageCount === 1 ? '' : 's'}` : null,
    videoCount > 0 ? `${videoCount} video${videoCount === 1 ? '' : 's'}` : null,
  ].filter((part): part is string => part !== null);

  if (parts.length === 0) {
    return null;
  }

  return `${parts.join(', ')} attached`;
}

function formatTimestamp(timestamp: string) {
  if (!timestamp) return '';
  const date = new Date(timestamp);
  if (Number.isNaN(date.getTime())) return '';
  return date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
}

export function AgentChatToolGroup({ pairs }: AgentChatToolGroupProps) {
  const [isOpen, setIsOpen] = useState(false);
  const count = pairs.length;

  // For run commands, show the command string directly
  const commandSummaries = pairs.map((p) => {
    const command = p.call.tool_args?.command;
    return typeof command === 'string' ? command : (p.call.content ?? p.call.tool_name ?? 'tool');
  });

  const label = count === 1
    ? commandSummaries[0]
    : `${count} commands`;

  return (
    <div className="w-full">
      <button
        type="button"
        className="flex w-full items-center gap-2 rounded-lg bg-muted/30 px-2.5 py-1.5 text-left text-xs transition-colors hover:bg-muted/50"
        onClick={() => setIsOpen(!isOpen)}
      >
        <Terminal className="h-3 w-3 shrink-0 text-muted-foreground" />
        <code className="flex-1 truncate font-mono text-foreground/80">{label}</code>
        {count > 1 && (isOpen ? <ChevronDown className="h-3 w-3 shrink-0 text-muted-foreground" /> : <ChevronRight className="h-3 w-3 shrink-0 text-muted-foreground" />)}
      </button>

      {isOpen && count > 1 && (
        <div className="mt-1 space-y-0.5 pl-2">
          {pairs.map((pair, index) => (
            <div key={`${pair.call.timestamp}:${index}`} className="flex items-start gap-2 rounded px-2 py-1 text-xs">
              <code className="font-mono text-foreground/70">{commandSummaries[index]}</code>
              {pair.result && (
                <span className="truncate text-muted-foreground">→ {pair.result.content?.slice(0, 80)}</span>
              )}
            </div>
          ))}
        </div>
      )}

      {/* Show result inline for single commands */}
      {count === 1 && pairs[0].result?.content && (
        <div className="mt-0.5 px-2.5 text-xs text-muted-foreground">
          {pairs[0].result.content.slice(0, 120)}
        </div>
      )}
    </div>
  );
}

export function AgentChatMessage({ turn }: AgentChatMessageProps) {
  const timestamp = formatTimestamp(turn.timestamp);
  const isUser = turn.role === 'user';
  const attachmentSummary = formatAttachmentSummary(turn.attachments);

  return (
    <div className={cn('flex w-full', isUser ? 'justify-end' : 'justify-start')}>
      <div
        className={cn(
          'max-w-[85%] rounded-2xl px-4 py-2.5 shadow-sm',
          isUser
            ? 'bg-primary text-primary-foreground'
            : 'border border-border/70 bg-card text-card-foreground',
        )}
      >
        <div className="whitespace-pre-wrap text-sm leading-relaxed">{turn.content}</div>
        {attachmentSummary && (
          <span
            className={cn(
              'mt-1.5 block text-xs',
              isUser ? 'text-primary-foreground/75' : 'text-muted-foreground',
            )}
          >
            {attachmentSummary}
          </span>
        )}
        {timestamp && (
          <div
            className={cn(
              'mt-1.5 text-[10px] uppercase tracking-[0.14em]',
              isUser ? 'text-primary-foreground/70' : 'text-muted-foreground',
            )}
          >
            {timestamp}
          </div>
        )}
      </div>
    </div>
  );
}

import { useCallback, useEffect, useMemo, useRef, useState, type RefObject } from 'react';
import type { GallerySelectionItem } from '@/shared/contexts/GallerySelectionContext';
import type { GeneratedImageWithMetadata } from '@/shared/components/MediaGallery/types';

type SelectionRect = {
  left: number;
  top: number;
  width: number;
  height: number;
};

type UseLassoSelectionParams = {
  containerRef: RefObject<HTMLElement | null>;
  items: GeneratedImageWithMetadata[];
  onSelectItems: (items: GallerySelectionItem[], options?: { append?: boolean }) => void;
};

type DragState = {
  startX: number;
  startY: number;
  append: boolean;
};

function toSelectionItem(image: GeneratedImageWithMetadata): GallerySelectionItem {
  return {
    id: image.id,
    url: image.url,
    type: image.type ?? image.contentType ?? (image.isVideo ? 'video/mp4' : 'image/png'),
    generationId: image.generation_id ?? image.id,
  };
}

function rectsIntersect(a: DOMRect, b: DOMRect) {
  return !(a.right < b.left || a.left > b.right || a.bottom < b.top || a.top > b.bottom);
}

export function useLassoSelection({
  containerRef,
  items,
  onSelectItems,
}: UseLassoSelectionParams) {
  const [selectionRect, setSelectionRect] = useState<SelectionRect | null>(null);
  const dragStateRef = useRef<DragState | null>(null);

  const itemsById = useMemo(
    () => new Map(items.map((item) => [item.id, item])),
    [items],
  );

  const endSelection = useCallback((clientX: number, clientY: number) => {
    const container = containerRef.current;
    const dragState = dragStateRef.current;

    if (!container || !dragState) {
      dragStateRef.current = null;
      setSelectionRect(null);
      return;
    }

    const normalizedRect = new DOMRect(
      Math.min(dragState.startX, clientX),
      Math.min(dragState.startY, clientY),
      Math.abs(clientX - dragState.startX),
      Math.abs(clientY - dragState.startY),
    );

    const selectedItems = Array.from(
      container.querySelectorAll<HTMLElement>('[data-gallery-item-id]'),
    ).flatMap((element) => {
      const itemId = element.dataset.galleryItemId;
      const image = itemId ? itemsById.get(itemId) : undefined;
      if (!image) {
        return [];
      }

      return rectsIntersect(normalizedRect, element.getBoundingClientRect())
        ? [toSelectionItem(image)]
        : [];
    });

    onSelectItems(selectedItems, { append: dragState.append });
    dragStateRef.current = null;
    setSelectionRect(null);
  }, [containerRef, itemsById, onSelectItems]);

  useEffect(() => {
    const handleMouseMove = (event: MouseEvent) => {
      const dragState = dragStateRef.current;
      const container = containerRef.current;
      if (!dragState || !container) {
        return;
      }

      const bounds = container.getBoundingClientRect();
      const currentX = Math.min(Math.max(event.clientX, bounds.left), bounds.right);
      const currentY = Math.min(Math.max(event.clientY, bounds.top), bounds.bottom);
      const left = Math.min(dragState.startX, currentX) - bounds.left;
      const top = Math.min(dragState.startY, currentY) - bounds.top;

      setSelectionRect({
        left,
        top,
        width: Math.abs(currentX - dragState.startX),
        height: Math.abs(currentY - dragState.startY),
      });
    };

    const handleMouseUp = (event: MouseEvent) => {
      endSelection(event.clientX, event.clientY);
    };

    window.addEventListener('mousemove', handleMouseMove);
    window.addEventListener('mouseup', handleMouseUp);

    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
    };
  }, [containerRef, endSelection]);

  const handleMouseDown = useCallback((event: React.MouseEvent<HTMLElement>) => {
    if (event.button !== 0) {
      return;
    }

    const container = containerRef.current;
    const target = event.target as HTMLElement;
    if (!container || target.closest('[data-gallery-item-id]')) {
      return;
    }

    const bounds = container.getBoundingClientRect();
    dragStateRef.current = {
      startX: event.clientX,
      startY: event.clientY,
      append: event.shiftKey || event.metaKey || event.ctrlKey,
    };
    setSelectionRect({
      left: event.clientX - bounds.left,
      top: event.clientY - bounds.top,
      width: 0,
      height: 0,
    });
    event.preventDefault();
  }, [containerRef]);

  return {
    selectionRect,
    handleMouseDown,
  };
}

