import { useCallback, useRef } from 'react';
import type { GeneratedImageWithMetadata } from '@/shared/components/MediaGallery/types';
import { captureTouchStartPoint, isTouchTapWithinThreshold } from '@/shared/lib/touch/touchGestureUtils';

interface UseItemInteractionParams {
  image: GeneratedImageWithMetadata;
  isMobile: boolean;
  mobileActiveImageId: string | null;
  enableSingleClick: boolean;
  onImageClick?: (image: GeneratedImageWithMetadata) => void;
  onMobileTap: (image: GeneratedImageWithMetadata) => void;
}

export function useItemInteraction({
  image,
  isMobile,
  mobileActiveImageId,
  enableSingleClick,
  onImageClick,
  onMobileTap,
}: UseItemInteractionParams) {
  const touchStartPosRef = useRef<{ x: number; y: number } | null>(null);

  const handleTouchStart = useCallback((event: React.TouchEvent) => {
    captureTouchStartPoint(touchStartPosRef, event);
  }, []);

  const handleInteraction = useCallback((event: React.TouchEvent | React.MouseEvent) => {
    const path = (event.nativeEvent as Event)?.composedPath?.() as HTMLElement[] | undefined;
    const isInsideButton = path
      ? path.some((element) => (element as HTMLElement)?.tagName === 'BUTTON' || (element as HTMLElement)?.closest?.('button'))
      : Boolean((event.target as HTMLElement).closest('button'));

    const isItemActive = mobileActiveImageId === image.id;
    if (isInsideButton && isItemActive) {
      return;
    }

    if (event.type === 'touchend') {
      const isTap = isTouchTapWithinThreshold(
        touchStartPosRef,
        event as React.TouchEvent,
        10,
      );
      if (!isTap) {
        return;
      }
    }

    event.preventDefault();

    if (enableSingleClick && onImageClick) {
      onImageClick(image);
      return;
    }

    if (isMobile) {
      onMobileTap(image);
    }
  }, [mobileActiveImageId, image, enableSingleClick, onImageClick, isMobile, onMobileTap]);

  return {
    handleTouchStart,
    handleInteraction,
  };
}

import React from "react";
import { HoverScrubVideo } from "@/shared/components/media/HoverScrubVideo";
import type { GeneratedImageWithMetadata } from "../../MediaGallery/types";

interface VideoContentProps {
  image: GeneratedImageWithMetadata;
  stableDisplayUrl: string;
  stableVideoUrl: string | null;
  actualSrc: string | null;
  shouldLoad: boolean;
  imageLoaded: boolean;
  videosAsThumbnails: boolean;
  isMobile: boolean;
  enableSingleClick: boolean;
  onImageClick?: (image: GeneratedImageWithMetadata) => void;
  onOpenLightbox: (image: GeneratedImageWithMetadata) => void;
  onTouchStart?: (e: React.TouchEvent) => void;
  onTouchEnd?: (e: React.TouchEvent) => void;
  onVideoError: (e?: React.SyntheticEvent) => void;
  onLoadStart: () => void;
  onLoadedData: () => void;
}

export const VideoContent: React.FC<VideoContentProps> = ({
  image,
  stableDisplayUrl,
  stableVideoUrl,
  actualSrc,
  shouldLoad,
  imageLoaded,
  videosAsThumbnails,
  isMobile,
  enableSingleClick,
  onImageClick,
  onOpenLightbox,
  onTouchStart,
  onTouchEnd,
  onVideoError,
  onLoadStart,
  onLoadedData,
}) => {
  if (videosAsThumbnails) {
    // Lightweight thumbnail mode - just show a static image for video selection panels
    return (
      <div className="absolute inset-0 w-full h-full">
        <img
          src={stableDisplayUrl || ''}
          alt={image.prompt || ''}
          className="w-full h-full object-cover cursor-pointer"
          loading="lazy"
          onClick={enableSingleClick || !isMobile ? () => {
            if (onImageClick) onImageClick(image);
            else onOpenLightbox(image);
          } : undefined}
          onDoubleClick={isMobile ? undefined : () => onOpenLightbox(image)}
        />
        {/* Video indicator overlay */}
        <div className="absolute inset-0 flex items-center justify-center bg-black/10 pointer-events-none">
          <div className="w-10 h-10 rounded-full bg-black/50 flex items-center justify-center">
            <svg className="w-5 h-5 text-white ml-0.5" fill="currentColor" viewBox="0 0 24 24">
              <path d="M8 5v14l11-7z"/>
            </svg>
          </div>
        </div>
      </div>
    );
  }

  // Full HoverScrubVideo mode for galleries that need scrubbing
  return (
    <>
      {/* Thumbnail overlay - stays visible until video is loaded to prevent flash */}
      {stableDisplayUrl && !imageLoaded && (
        <img
          src={stableDisplayUrl}
          alt=""
          className="absolute inset-0 w-full h-full object-cover z-[1] pointer-events-none"
          loading="eager"
        />
      )}
      <HoverScrubVideo
        src={stableVideoUrl || actualSrc || ''}
        poster={stableDisplayUrl || undefined}
        preload={shouldLoad ? "auto" : "none"}
        className="absolute inset-0 w-full h-full"
        videoClassName="object-cover cursor-pointer w-full h-full"
        muted
        loop
        onClick={enableSingleClick || !isMobile ? () => {
          if (onImageClick) onImageClick(image);
          else onOpenLightbox(image);
        } : undefined}
        onDoubleClick={isMobile ? undefined : () => onOpenLightbox(image)}
        onTouchStart={isMobile && !enableSingleClick ? onTouchStart : undefined}
        onTouchEnd={isMobile && !enableSingleClick ? onTouchEnd : undefined}
        onVideoError={onVideoError}
        onLoadStart={onLoadStart}
        onLoadedData={onLoadedData}
      />
    </>
  );
};

import React from "react";
import { AlertTriangle } from "lucide-react";
import { cn } from '@/shared/components/ui/contracts/cn';
import type { GeneratedImageWithMetadata } from "../../MediaGallery/types";

interface ImageContentProps {
  image: GeneratedImageWithMetadata;
  index: number;
  actualSrc: string | null;
  imageLoaded: boolean;
  imageLoadError: boolean;
  progressiveEnabled: boolean;
  isThumbShowing: boolean;
  isFullLoaded: boolean;
  progressiveRef: React.Ref<HTMLImageElement>;
  isMobile: boolean;
  enableSingleClick?: boolean;
  onImageClick?: (image: GeneratedImageWithMetadata) => void;
  onOpenLightbox: (image: GeneratedImageWithMetadata) => void;
  onImageLoad: () => void;
  onImageError: (e?: React.SyntheticEvent) => void;
  onRetry: () => void;
  setImageLoading: (loading: boolean) => void;
}

export const ImageContent: React.FC<ImageContentProps> = ({
  image,
  index,
  actualSrc,
  imageLoaded,
  imageLoadError,
  progressiveEnabled,
  isThumbShowing,
  isFullLoaded,
  progressiveRef,
  isMobile,
  enableSingleClick,
  onImageClick,
  onOpenLightbox,
  onImageLoad,
  onImageError,
  onRetry,
  setImageLoading,
}) => {
  if (imageLoadError) {
    return (
      <div className="absolute inset-0 w-full h-full flex items-center justify-center bg-gray-100 text-gray-500">
        <div className="text-center">
          <AlertTriangle className="h-8 w-8 mx-auto mb-2 opacity-50" />
          <p className="text-xs">Failed to load image</p>
          <button
            onClick={onRetry}
            className="text-xs underline hover:no-underline mt-1"
          >
            Retry
          </button>
        </div>
      </div>
    );
  }

  return (
    <>
      {/* Show image once it's loaded, regardless of shouldLoad state */}
      {actualSrc && imageLoaded && (
        <img
          ref={progressiveRef}
          src={actualSrc}
          alt={image.prompt || `Generated image ${index + 1}`}
          className={cn(
            "absolute inset-0 w-full h-full object-cover group-hover:opacity-80 transition-all duration-300",
            progressiveEnabled && isThumbShowing && "opacity-90",
            progressiveEnabled && isFullLoaded && "opacity-100"
          )}
          onClick={enableSingleClick || !isMobile ? () => {
            if (onImageClick) {
              onImageClick(image);
            } else {
              onOpenLightbox(image);
            }
          } : undefined}
          onDoubleClick={isMobile ? undefined : () => onOpenLightbox(image)}
          draggable={false}
          style={{ cursor: 'pointer' }}
        />
      )}

      {/* Hidden image for background loading - only when image hasn't loaded yet */}
      {actualSrc && !imageLoaded && (
        <img
          src={actualSrc}
          alt={image.prompt || `Generated image ${index + 1}`}
          style={{ display: 'none' }}
          onError={onImageError}
          onLoad={onImageLoad}
          onLoadStart={() => setImageLoading(true)}
          onAbort={() => setImageLoading(false)}
        />
      )}

      {/* Show skeleton only while the media is still loading */}
      {!imageLoaded && (
        <div className="absolute inset-0 w-full h-full flex items-center justify-center bg-muted/30 animate-pulse pointer-events-none">
          <div className="h-8 w-8 animate-spin rounded-full border-b-2 border-gray-400"></div>
        </div>
      )}
    </>
  );
};

