import { parseCommand, validateCommand, type ParsedCommand } from "../command-parser.ts";
import { loadTimelineState, saveTimelineConfigVersioned } from "../db.ts";
import type {
  SupabaseAdmin,
  TimelineState,
  ToolContext,
  ToolResult,
} from "../types.ts";
import { handlers as timelineHandlers } from "./timeline.ts";
import { createGenerationTask } from "./generation.ts";

// Map parsed command types to timeline tool names
const COMMAND_TO_TOOL: Record<string, string> = {
  view: "view_timeline",
  move: "move_clip",
  trim: "trim_clip",
  delete: "delete_clip",
  set: "set_clip_property",
  "set-text": "set_text_content",
  duplicate: "duplicate_clip",
  "add-text": "add_text_clip",
  "find-issues": "find_issues",
  // "repeat" is handled specially in executeCommand, not mapped to a tool
};

function commandToToolArgs(parsed: ParsedCommand): Record<string, unknown> {
  switch (parsed.type) {
    case "view": return {};
    case "move": return { clipId: parsed.clipId, at: parsed.at };
    case "trim": return { clipId: parsed.clipId, from: parsed.from, to: parsed.to, duration: parsed.duration };
    case "delete": return { clipId: parsed.clipId };
    case "set-text": return { clipId: parsed.clipId, text: parsed.text };
    case "duplicate": return { clipId: parsed.clipId, count: parsed.count };
    case "set": return { clipId: parsed.clipId, property: parsed.property, value: parsed.value };
    case "add-text": return { track: parsed.track, at: parsed.at, duration: parsed.duration, text: parsed.text };
    case "find-issues": return {};
    case "generate": return { prompt: parsed.prompt, count: parsed.count };
    default: return {};
  }
}

function buildContext(state: TimelineState): ToolContext {
  return {
    config: state.config,
    registry: state.registry,
    projectId: state.projectId,
  };
}

export async function executeCommand(
  command: string,
  state: TimelineState,
  timelineId: string,
  supabaseAdmin: SupabaseAdmin,
): Promise<ToolResult> {
  const parsed = parseCommand(command);

  if (parsed.type === "error") {
    return { result: parsed.message };
  }

  // Validate against current timeline state
  const validationError = validateCommand(parsed, state.config, state.registry);
  if (validationError) {
    return { result: validationError };
  }

  // Handle repeat: expand template, execute all in memory, save once at end
  if (parsed.type === "repeat") {
    const errorMessages: string[] = [];
    let errors = 0;
    let succeeded = 0;

    for (let i = 0; i < parsed.count; i++) {
      const value = parsed.from + parsed.step * i;
      const roundedValue = Math.round(value * 1000) / 1000;
      const expanded = parsed.template.replace(
        new RegExp(`\\{${parsed.varName}\\}`, "g"),
        String(roundedValue),
      );

      // Parse and validate the sub-command but execute in memory only (no DB save)
      const subParsed = parseCommand(expanded);
      if (subParsed.type === "error") {
        errorMessages.push(`${i + 1}. ${subParsed.message}`);
        errors++;
        if (errors >= 3) { errorMessages.push("Stopped after 3 errors."); break; }
        continue;
      }

      const subValidation = validateCommand(subParsed, state.config, state.registry);
      if (subValidation) {
        errorMessages.push(`${i + 1}. ${subValidation}`);
        errors++;
        if (errors >= 3) { errorMessages.push("Stopped after 3 errors."); break; }
        continue;
      }

      const toolName = COMMAND_TO_TOOL[subParsed.type];
      const handler = toolName ? timelineHandlers[toolName] : undefined;
      if (!handler) {
        errorMessages.push(`${i + 1}. No handler for "${subParsed.type}".`);
        errors++;
        continue;
      }

      const args = commandToToolArgs(subParsed);
      const ctx = buildContext(state);
      const result = await handler(args, ctx);

      if (result.config) {
        // Apply to in-memory state without saving to DB
        state.config = result.config;
      }
      succeeded++;
    }

    // Save once at the end
    if (succeeded > 0) {
      const nextVersion = await saveTimelineConfigVersioned(
        supabaseAdmin, timelineId, state.configVersion, state.config,
      );
      if (nextVersion !== null) {
        state.configVersion = nextVersion;
      } else {
        return { result: `Executed ${succeeded} commands in memory but failed to save — version conflict.` };
      }
    }

    return {
      config: succeeded > 0 ? state.config : undefined,
      result: `Repeated ${succeeded}/${parsed.count}.${errorMessages.length > 0 ? "\n" + errorMessages.join("\n") : ""}`,
    };
  }

  // Handle generation separately (async, not a timeline tool)
  if (parsed.type === "generate") {
    return await createGenerationTask({
      project_id: state.projectId,
      prompt: parsed.prompt,
      count: parsed.count,
    });
  }

  // Route to timeline tool
  const toolName = COMMAND_TO_TOOL[parsed.type];
  const handler = toolName ? timelineHandlers[toolName] : undefined;
  if (!handler) {
    return { result: `Internal error: no handler for command type "${parsed.type}".` };
  }

  const args = commandToToolArgs(parsed);
  const ctx = buildContext(state);

  const runTool = () => handler(args, ctx);
  let result = await runTool();

  if (!result.config) {
    return result;
  }

  // Versioned save with retry
  let nextVersion = await saveTimelineConfigVersioned(
    supabaseAdmin,
    timelineId,
    state.configVersion,
    result.config,
  );

  if (nextVersion !== null) {
    state.config = result.config;
    state.configVersion = nextVersion;
    return result;
  }

  // Reload and retry once on version conflict
  const refreshedState = await loadTimelineState(supabaseAdmin, timelineId);
  state.config = refreshedState.config;
  state.configVersion = refreshedState.configVersion;
  state.registry = refreshedState.registry;
  state.projectId = refreshedState.projectId;

  const retryCtx = buildContext(state);
  result = await handler(args, retryCtx);
  if (!result.config) {
    return { result: `${result.result} (retried after reload.)` };
  }

  nextVersion = await saveTimelineConfigVersioned(
    supabaseAdmin,
    timelineId,
    state.configVersion,
    result.config,
  );

  if (nextVersion === null) {
    return { result: "Version conflict. Please retry." };
  }

  state.config = result.config;
  state.configVersion = nextVersion;
  return { ...result, result: `${result.result} (retried after reload.)` };
}

import {
  extractAssistantText,
  isRecord,
  parseToolArgsSafely,
} from "./llm/messages.ts";

export type ExtractedToolCall = {
  id: string;
  name: string;
  args: Record<string, unknown>;
  parseError: string | null;
};

const COMMAND_VERBS = /^(?:view|move|trim|delete|rm|set|set-text|settext|add-text|addtext|text|duplicate|dup|clone|find-issues|findissues|issues|generate|gen)\b/;

function cleanCommand(raw: string): string {
  return raw
    .replace(/\\"/g, "\"")
    .replace(/\\'/g, "'")
    .replace(/^["']+|["']+$/g, "")
    .trim();
}

export function extractToolCalls(responseMessage: Record<string, unknown>): ExtractedToolCall[] {
  const rawToolCalls = Array.isArray((responseMessage as { tool_calls?: unknown[] }).tool_calls)
    ? (responseMessage as { tool_calls: unknown[] }).tool_calls
    : [];
  const structuredToolCalls = rawToolCalls.flatMap((toolCall) => {
    if (!isRecord(toolCall)) return [];
    const fn = isRecord(toolCall.function) ? toolCall.function : undefined;
    if (!fn || typeof fn.name !== "string" || !fn.name.trim()) return [];
    const { args, error } = parseToolArgsSafely(typeof fn.arguments === "string" ? fn.arguments : "{}");
    return [{
      id: typeof toolCall.id === "string" && toolCall.id.trim() ? toolCall.id : crypto.randomUUID(),
      name: fn.name,
      args,
      parseError: error,
    }];
  });
  if (structuredToolCalls.length > 0) return structuredToolCalls;

  const text = extractAssistantText(responseMessage);
  if (!text) return [];

  const toolCalls: ExtractedToolCall[] = [];
  const runRe = /run\s*\(\s*(?:command\s*=\s*)?["']([^"']+)["']\s*\)/g;
  let match: RegExpExecArray | null;
  while ((match = runRe.exec(text)) !== null) {
    toolCalls.push({
      id: crypto.randomUUID(),
      name: "run",
      args: { command: cleanCommand(match[1]) },
      parseError: null,
    });
  }
  if (toolCalls.length > 0) return toolCalls;

  for (const line of text.split("\n")) {
    const stripped = line.replace(/^\s*\d+[.):-]\s*/, "").trim();
    if (!stripped || !COMMAND_VERBS.test(stripped)) continue;
    toolCalls.push({
      id: crypto.randomUUID(),
      name: "run",
      args: { command: cleanCommand(stripped) },
      parseError: null,
    });
  }
  if (toolCalls.length > 0) return toolCalls;

  const patterns = [
    /Tool call run:\s*\n?\{?\s*"?command"?\s*[:=]\s*"([^"]+)"/,
    /<parameter\s+name="command">([^<]+)<\/parameter>/,
    /\[TOOL_CALL\][\s\S]*?--command\s+"([^"]+)"[\s\S]*?\[\/TOOL_CALL\]/,
    /command["\s:=]+["']([^"']+)["']/i,
  ];
  for (const pattern of patterns) {
    const inlineMatch = text.match(pattern);
    if (!inlineMatch) continue;
    return [{
      id: crypto.randomUUID(),
      name: "run",
      args: { command: cleanCommand(inlineMatch[1]) },
      parseError: null,
    }];
  }

  return [];
}

export function isToolError(result: string): boolean {
  return result.includes("not found")
    || result.includes("does not exist")
    || result.includes("requires")
    || result.includes("must be")
    || result.includes("Failed")
    || result.includes("Unknown command")
    || result.includes("Unknown tool")
    || result.includes("error");
}

import type { TimelineConfig, AssetRegistry } from "../../src/tools/video-editor/types/index.ts";

export type ParsedCommand =
  | { type: "view" }
  | { type: "move"; clipId: string; at: number }
  | { type: "trim"; clipId: string; from?: number; to?: number; duration?: number }
  | { type: "delete"; clipId: string }
  | { type: "set"; clipId: string; property: string; value: number }
  | { type: "add-text"; track: string; at: number; duration: number; text: string }
  | { type: "set-text"; clipId: string; text: string }
  | { type: "duplicate"; clipId: string; count: number }
  | { type: "repeat"; count: number; varName: string; from: number; step: number; template: string }
  | { type: "find-issues" }
  | { type: "generate"; prompt: string; count: number }
  | { type: "error"; message: string };

const SETTABLE_PROPERTIES = new Set(["volume", "speed", "opacity", "x", "y", "width", "height"]);

type CommandParser = (tokens: string[]) => ParsedCommand;

function parseNumber(raw: string, label: string): number | string {
  const n = Number(raw);
  if (Number.isNaN(n)) return `${label} must be a number, got "${raw}"`;
  return n;
}

function parseFlag(args: string[], flag: string): string | undefined {
  const idx = args.indexOf(flag);
  if (idx === -1 || idx + 1 >= args.length) return undefined;
  return args[idx + 1];
}

function tokenizeCommand(trimmed: string): string[] {
  const tokens: string[] = [];
  const re = /"([^"]*)"|\S+/g;
  let match: RegExpExecArray | null;
  while ((match = re.exec(trimmed)) !== null) {
    tokens.push(match[1] ?? match[0]);
  }
  return tokens;
}

function parseViewCommand(): ParsedCommand {
  return { type: "view" };
}

function parseFindIssuesCommand(): ParsedCommand {
  return { type: "find-issues" };
}

function parseMoveCommand(tokens: string[]): ParsedCommand {
  if (tokens.length < 3) return { type: "error", message: "Usage: move <clipId> <seconds>" };
  const at = parseNumber(tokens[2], "seconds");
  if (typeof at === "string") return { type: "error", message: at };
  if (at < 0) return { type: "error", message: "seconds must be >= 0" };
  return { type: "move", clipId: tokens[1], at };
}

function parseTrimCommand(tokens: string[]): ParsedCommand {
  if (tokens.length < 2) return { type: "error", message: "Usage: trim <clipId> [--from N] [--to N] [--duration N]" };
  const clipId = tokens[1];
  const rest = tokens.slice(2);
  const fromRaw = parseFlag(rest, "--from");
  const toRaw = parseFlag(rest, "--to");
  const durRaw = parseFlag(rest, "--duration");

  const from = fromRaw ? parseNumber(fromRaw, "--from") : undefined;
  if (typeof from === "string") return { type: "error", message: from };
  const to = toRaw ? parseNumber(toRaw, "--to") : undefined;
  if (typeof to === "string") return { type: "error", message: to };
  const duration = durRaw ? parseNumber(durRaw, "--duration") : undefined;
  if (typeof duration === "string") return { type: "error", message: duration };

  if (from === undefined && to === undefined && duration === undefined) {
    return { type: "error", message: "trim requires at least one of --from, --to, --duration" };
  }
  if (duration !== undefined && duration <= 0) {
    return { type: "error", message: "--duration must be > 0" };
  }

  return { type: "trim", clipId, from, to, duration };
}

function parseDeleteCommand(tokens: string[]): ParsedCommand {
  if (tokens.length < 2) return { type: "error", message: "Usage: delete <clipId>" };
  return { type: "delete", clipId: tokens[1] };
}

function parseSetCommand(tokens: string[]): ParsedCommand {
  if (tokens.length < 4) return { type: "error", message: "Usage: set <clipId> <property> <value>" };
  const property = tokens[2].toLowerCase();
  if (!SETTABLE_PROPERTIES.has(property)) {
    return { type: "error", message: `Unknown property "${property}". Valid: ${[...SETTABLE_PROPERTIES].join(", ")}` };
  }
  const value = parseNumber(tokens[3], "value");
  if (typeof value === "string") return { type: "error", message: value };
  return { type: "set", clipId: tokens[1], property, value };
}

function parseAddTextCommand(tokens: string[]): ParsedCommand {
  if (tokens.length < 5) return { type: "error", message: 'Usage: add-text <track> <at> <duration> "<text>"' };
  const at = parseNumber(tokens[2], "at");
  if (typeof at === "string") return { type: "error", message: at };
  const duration = parseNumber(tokens[3], "duration");
  if (typeof duration === "string") return { type: "error", message: duration };
  if (duration <= 0) return { type: "error", message: "duration must be > 0" };
  const text = tokens.slice(4).join(" ");
  return { type: "add-text", track: tokens[1], at, duration, text };
}

function parseSetTextCommand(tokens: string[]): ParsedCommand {
  if (tokens.length < 3) return { type: "error", message: 'Usage: set-text <clipId> "<new text>"' };
  const text = tokens.slice(2).join(" ");
  return { type: "set-text", clipId: tokens[1], text };
}

function parseDuplicateCommand(tokens: string[]): ParsedCommand {
  if (tokens.length < 2) return { type: "error", message: "Usage: duplicate <clipId> [count]" };
  const countRaw = tokens[2];
  const count = countRaw ? parseNumber(countRaw, "count") : 1;
  if (typeof count === "string") return { type: "error", message: count };
  return { type: "duplicate", clipId: tokens[1], count: Math.max(1, Math.round(count)) };
}

function parseRepeatCommand(tokens: string[]): ParsedCommand {
  const rest = tokens.slice(1);
  if (rest.length < 2) return { type: "error", message: "Usage: repeat <count> <command...> --start <N> --gap <N>" };

  const count = parseNumber(rest[0], "count");
  if (typeof count === "string") return { type: "error", message: count };
  if (count <= 0 || count > 500) return { type: "error", message: "count must be 1-500" };

  const commandTokens = rest.slice(1);
  const startRaw = parseFlag(commandTokens, "--start") ?? parseFlag(commandTokens, "--from") ?? parseFlag(commandTokens, "--at");
  const gapRaw = parseFlag(commandTokens, "--gap") ?? parseFlag(commandTokens, "--step") ?? parseFlag(commandTokens, "--interval");
  const varName = parseFlag(commandTokens, "--var") ?? "i";

  const from = startRaw ? parseNumber(startRaw, "--start") : 0;
  if (typeof from === "string") return { type: "error", message: from };
  const step = gapRaw ? parseNumber(gapRaw, "--gap") : 1;
  if (typeof step === "string") return { type: "error", message: step };

  const flagKeys = new Set(["--start", "--from", "--at", "--gap", "--step", "--interval", "--var"]);
  const skipIndices = new Set<number>();
  for (let idx = 0; idx < commandTokens.length; idx++) {
    if (flagKeys.has(commandTokens[idx]) && idx + 1 < commandTokens.length) {
      skipIndices.add(idx);
      skipIndices.add(idx + 1);
      idx++;
    }
  }
  let template = commandTokens.filter((_, idx) => !skipIndices.has(idx)).join(" ");

  if (!template.includes(`{${varName}}`)) {
    const parts = template.split(" ");
    if (parts[0] === "add-text" && parts.length >= 3) {
      parts.splice(2, 0, `{${varName}}`);
      template = parts.join(" ");
    }
  }

  if (!template) return { type: "error", message: "Usage: repeat <count> <command...> --start <N> --gap <N>" };

  return { type: "repeat", count: Math.round(count), varName, from, step, template };
}

function parseGenerateCommand(tokens: string[]): ParsedCommand {
  if (tokens.length < 2) return { type: "error", message: "Usage: generate <prompt> [--count N]" };
  const rest = tokens.slice(1);
  const countRaw = parseFlag(rest, "--count");
  const count = countRaw ? parseNumber(countRaw, "--count") : 1;
  if (typeof count === "string") return { type: "error", message: count };
  const prompt = rest.filter((token) => token !== "--count" && token !== countRaw).join(" ");
  if (!prompt) return { type: "error", message: "generate requires a prompt" };
  return { type: "generate", prompt, count: Math.max(1, Math.round(count)) };
}

const COMMAND_ALIASES: Record<string, string> = {
  findissues: "find-issues",
  issues: "find-issues",
  rm: "delete",
  addtext: "add-text",
  text: "add-text",
  settext: "set-text",
  "update-text": "set-text",
  dup: "duplicate",
  clone: "duplicate",
  gen: "generate",
};

const PARSERS: Record<string, CommandParser> = {
  view: parseViewCommand,
  "find-issues": parseFindIssuesCommand,
  move: parseMoveCommand,
  trim: parseTrimCommand,
  delete: parseDeleteCommand,
  set: parseSetCommand,
  "add-text": parseAddTextCommand,
  "set-text": parseSetTextCommand,
  duplicate: parseDuplicateCommand,
  repeat: parseRepeatCommand,
  generate: parseGenerateCommand,
};

export function parseCommand(raw: string): ParsedCommand {
  const trimmed = raw.trim();
  if (!trimmed) return { type: "error", message: "Empty command." };

  const tokens = tokenizeCommand(trimmed);
  const command = tokens[0]?.toLowerCase();
  const normalizedCommand = command ? (COMMAND_ALIASES[command] ?? command) : "";
  const parser = normalizedCommand ? PARSERS[normalizedCommand] : undefined;

  if (parser) {
    return parser(tokens);
  }

  return {
    type: "error",
    message: `Unknown command "${command}". Available: view, move, trim, delete, set, add-text, find-issues. For generation requests, use create_task (legacy generate still works).`,
  };
}

/** Validate a parsed command against the current timeline state. */
export function validateCommand(
  parsed: ParsedCommand,
  config: TimelineConfig,
  _registry: AssetRegistry,
): string | null {
  if (parsed.type === "error" || parsed.type === "view" || parsed.type === "find-issues" || parsed.type === "generate") {
    return null;
  }

  // Validate clipId exists
  if ("clipId" in parsed) {
    const clip = config.clips.find((c) => c.id === parsed.clipId);
    if (!clip) {
      const ids = config.clips.map((c) => c.id).join(", ");
      return `Clip "${parsed.clipId}" not found. Available: ${ids}`;
    }
  }

  // Validate track exists for add-text
  if (parsed.type === "add-text") {
    const tracks = config.tracks ?? [];
    if (tracks.length > 0 && !tracks.some((t) => t.id === parsed.track)) {
      const ids = tracks.map((t) => t.id).join(", ");
      return `Track "${parsed.track}" not found. Available: ${ids}`;
    }
  }

  return null;
}

