197	): Promise<RunAgentLoopResult> {
198	  const { session, userMessage, selectedClips, supabaseAdmin, logger } = options;
199	
200	  const lastTurn = session.turns[session.turns.length - 1];
201	  const isDuplicate = userMessage && lastTurn?.role === "user" && lastTurn.content === userMessage;
202	  const turns = [...session.turns];
203	  if (userMessage && !isDuplicate) {
204	    const userTurn = createTurn("user", userMessage);
205	    attachSelectedClips(userTurn, selectedClips);
206	    turns.push(userTurn);
207	  }
208	  let status: AgentSessionStatus = "processing";
209	  const summary = session.summary;
210	  let activeToolCallId: string | null = null;
211	
212	  try {
213	    await persistSessionState(supabaseAdmin, {
214	      sessionId: session.id,
215	      status,
216	      turns,
217	      summary,
218	    });
219	
220	    const timelineState = await loadTimelineState(supabaseAdmin, session.timeline_id);
221	    const timelineSummary = viewTimeline(timelineState.config, timelineState.registry).result;
222	    const systemPrompt = buildTimelineAgentSystemPrompt({
223	      projectId: timelineState.projectId,
224	      timelineSummary,
225	      selectedClips,
226	    });
227	    const messages = buildInitialMessages(systemPrompt, turns);
228	    const startedAt = Date.now();
229	
230	    // Triage the user message to pick provider: easy/okay → Kimi K2.5, hard → Claude
231	    const difficulty = userMessage
232	      ? await triageDifficulty(userMessage, logger)
233	      : "okay";
234	
235	    for (let iteration = 0; iteration < LOOP_LIMIT; iteration += 1) {
236	      if (Date.now() - startedAt >= SOFT_TIMEOUT_MS) {
237	        status = "continue";
238	        break;
239	      }
240	
241	      const currentStatus = await loadSessionStatus(supabaseAdmin, session.id);
242	      if (currentStatus === "cancelled") {
243	        status = "cancelled";
244	        break;
245	      }
246	
247	      let completion;
248	      try {
249	        completion = await invokeLlm(
250	          {
251	            messages: messages as unknown[],
252	            tools: TIMELINE_AGENT_TOOLS as unknown[],
253	            tool_choice: "auto",
254	            temperature: 0.2,
255	            max_tokens: 4096,
256	            top_p: 1,
257	          },
258	          difficulty,
259	          logger,
260	        );
261	      } catch (llmError: unknown) {
262	        const text = `AI service error: ${toErrorMessage(llmError)}`;
263	        turns.push(createTurn("assistant", text));
264	        messages.push({ role: "assistant", content: text });
265	        status = "waiting_user";
266	        break;
267	      }
268	
269	      const responseMessage = completion.choices[0]?.message;
270	      if (!responseMessage) {
271	        turns.push(createTurn("assistant", "No response from AI."));
272	        status = "waiting_user";
273	        break;
274	      }
275	
276	      const extractedToolCalls = extractToolCalls(responseMessage);
277	      const assistantText = extractAssistantText(responseMessage);
278	
279	      if (extractedToolCalls.length === 0) {
280	        const text = assistantText || "What would you like me to do?";
281	        turns.push(createTurn("assistant", text));
282	        messages.push({ role: "assistant", content: text });
283	        status = "waiting_user";
284	        break;
285	      }
286	
287	      let hasError = false;
288	      if (extractedToolCalls.length > 0) {
289	        ({ hasError } = await processToolCalls({
290	          toolCalls: extractedToolCalls,
291	          assistantText,
292	          turns,
293	          messages,
294	          timelineState,
295	          selectedClips,
296	          supabaseAdmin,
297	          timelineId: session.timeline_id,
298	          setActiveToolCallId: (toolCallId) => { activeToolCallId = toolCallId; },
299	        }));
300	      }
301	
302	      if (hasError) {
303	        continue;
304	      }
305	    }
306	
307	    if (status === "processing") {
308	      status = "continue";
309	    }
310	
311	    await persistSessionState(supabaseAdmin, {
312	      sessionId: session.id,
313	      status,
314	      turns,
315	      summary,
316	    });
317	
318	    logger.info("Agent loop completed", {
319	      session_id: session.id,
320	      status,

320	      status,
321	      turns_added: turns.length - session.turns.length,
322	    });
323	
324	    return { status, turns, summary };
325	  } catch (error: unknown) {
326	    const errorDetail = toErrorMessage(error);
327	    console.error(`[agent] FATAL: ${errorDetail}`);
328	    logger.error("Agent loop failed", {
329	      session_id: session.id,
330	      error: errorDetail,
331	    });
332	
333	    turns.push(
334	      activeToolCallId
335	        ? buildToolErrorTurn(activeToolCallId, error)
336	        : createTurn("assistant", `[INTERNAL ERROR] ${errorDetail}`),
337	    );
338	
339	    try {
340	      await persistSessionState(supabaseAdmin, {
341	        sessionId: session.id,
342	        status: "error",
343	        turns,
344	        summary,
345	      });
346	    } catch (persistError: unknown) {
347	      logger.error("Failed to persist error state", {
348	        session_id: session.id,
349	        error: toErrorMessage(persistError),
350	      });
351	    }
352	
353	    return { status: "error", turns, summary };
354	  }
355	}

